                                              sqlgen::sum("quantity"_c).as<"total_qty">(), 
                                              sqlgen::sum("amount"_c).as<"total_amt">())
                 .inner_join<Sale>("product_id"_c == "product_id"_c)
                 .group_by("category"_c)
                 .having(sqlgen::sum("amount"_c) > 5000.0)
                 .to<std::vector<CategoryReport>>;

