};

struct Sales {
  sqlgen::PrimaryKey<int> sale_id;
  int product_id;
  int quantity;
  sqlgen::Date sale_date;
};

struct TopProduct {
  int product_id;
  std::string product_name;
  std::string category;
  double total_sales;
};

/**
 * Description: This function retrieves the top products based on total sales.
 * Returns: std::vector<TopProduct>.
 */
std::vector<TopProduct> get_top_products(size_t limit_count = 10) {
  using namespace sqlgen;
  using namespace sqlgen::literals;

  auto conn = sqlite::connect("test_db.sqlite").value();
  drop<Product>(conn);
  drop<Sales>(conn);
  create_table<Product>(conn);
  create_table<Sales>(conn);

  const auto query =
      select_from<Product, "p">(col<"product_id", "p"> | as<"product_id">,
                                col<"product_name", "p"> | as<"product_name">,
                                col<"category", "p"> | as<"category">,
                                sum(col<"price", "p"> * col<"quantity", "s">) |
                                    as<"total_sales">) |
      inner_join<Sales, "s">(col<"product_id", "p"> == col<"product_id", "s">) |
      group_by(col<"product_id", "p">, col<"product_name", "p">, col<"category", "p">) |
      order_by("total_sales"_c.desc()) | limit(limit_count) |
      to<std::vector<TopProduct>>;

  return query(conn).value();
}

}  // namespace get_top_products

